import { IEnvironment } from './IEnvironment';

const baseUrl = require('$baseUrl');

export class Environment implements IEnvironment {

  public baseUrl: string = baseUrl || '/';

  public getWorkerUrl(moduleId: string, label: string) {
    const baseUrl = this.baseUrl;
    if (label === 'json') {
      return baseUrl + 'js/workers/json.worker.js';
    }
    if (label === 'css') {
      return baseUrl + 'js/workers/css.worker.js';
    }
    if (label === 'html') {
      return baseUrl + 'js/workers/html.worker.js';
    }
    if (label === 'typescript' || label === 'javascript') {
      return baseUrl + 'js/workers/ts.worker.js';
    }
    return baseUrl + 'js/workers/editor.worker.js';
  }
}

export const environment = new Environment();
(self as any).MonacoEnvironment = environment;